def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 0.0
        for j in range(1, 15):
            if j % 4 == 0:
                factor = 1.07 + 0.015 * j
            elif j % 6 == 0:
                factor = 0.93 - 0.01 * j
            else:
                factor = 1.0 + 0.005 * (j % 3)
            if ratio < 0.08 * j:
                term = ((j ** 3) / (1 + np.exp(ratio * j**1.5))) * factor
                score += term
            else:
                term = (np.log1p(j*j*j) + ratio**4) * factor / (j + 1.5)
                score += term
            if (cap * j + j*j) % 9 == 0:
                score *= 1.07
            elif (cap + j*j*j) % 11 == 0:
                score *= 0.94
            if j == 7:
                for k in range(1, 8):
                    delta = cap - item * (k**3)
                    if delta > 0:
                        if delta % (k+3) == 0:
                            penalty += (delta ** 0.4) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(delta)) / (k + 3)
                    else:
                        penalty -= abs(delta) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 2 == 1:
                adjustment *= 1.12 + 0.025 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.88 - 0.012 * j
            if j % 3 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio) * 0.6
            complexity += np.tanh(score * 0.01) * factor
        score += penalty * 0.75 + complexity * 0.5
        score *= adjustment
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap) / 2)
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.sqrt(cap) + 1.5) * (1 + ratio**1.1)
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2.2)
        if ratio > 0.9:
            priorities[i] *= 1.18
            if cap % 3 == 0:
                priorities[i] *= 1.05
            else:
                priorities[i] *= 0.97
        elif ratio < 0.04:
            priorities[i] *= 0.72
            if cap % 5 == 0:
                priorities[i] *= 1.03
            else:
                priorities[i] *= 0.99
        if cap % 2 == 0:
            priorities[i] *= 0.97 + 0.005 * (cap % 7)
        else:
            priorities[i] *= 1.03 - 0.004 * (cap % 5)
    return priorities
